-- La subconsulta calcula el promedio;
-- la consulta principal filtra con él
SELECT nombre, salario
FROM empleados
WHERE salario > (SELECT AVG(salario) FROM empleados);

-- Clientes que sí tienen pedidos
SELECT nombre FROM clientes c
WHERE EXISTS (
  SELECT 1 FROM pedidos p
  WHERE p.cliente_id = c.id
);

-- Clientes sin ningún pedido
SELECT nombre FROM clientes c
WHERE NOT EXISTS (
  SELECT 1 FROM pedidos p
  WHERE p.cliente_id = c.id
);
